-- SELECT operation (σ): Filter rows
-- σ_GPA>3.5 (Student)
SELECT * FROM Student WHERE gpa > 3.5;

-- PROJECT operation (π): Choose columns
-- π_name,gpa (Student)
SELECT name, gpa FROM Student;

-- Combined: π_name (σ_GPA>3.5 (Student))
SELECT name FROM Student WHERE gpa > 3.5;

-- UNION (∪): Combine relations
SELECT name FROM Students2023
UNION
SELECT name FROM Students2024;

-- DIFFERENCE (-): Remove tuples
SELECT name FROM AllStudents
EXCEPT
SELECT name FROM Graduates;

-- Two tables
CREATE TABLE Student (id INT, name VARCHAR(50));
CREATE TABLE Enrollment (student_id INT, course_id VARCHAR(10));

-- Natural Join (on common attributes)
-- Student ⋈ Enrollment
SELECT * FROM Student
NATURAL JOIN Enrollment;  -- Joins on same-named columns

-- Explicit Join (recommended)
SELECT s.id, s.name, e.course_id
FROM Student s
JOIN Enrollment e ON s.id = e.student_id;

-- Cartesian Product (×)
SELECT * FROM Student, Enrollment;
-- or
SELECT * FROM Student CROSS JOIN Enrollment;
